        /// </summary>
        public Int64 Tc1 {
            get { return mTc1; }
            set { mTc1 = value; NotifyUpdated(); }
        }

        /// <summary>
        /// Time sync timestamp 2. Timestamp of syncing component (mirrored in response).
        /// </summary>
        public Int64 Ts1 {
            get { return mTs1; }
            set { mTs1 = value; NotifyUpdated(); }
        }

